-- Manual fix: 2026-01-11 P2P -80 USDT had no plausible MP match (rate 2,000 was too high).
-- Proceeds actually went to Naranja X (better USDT rate that day). The +160,000 ARS that
-- landed in MP is a separate Naranja → MP transfer not modeled here.
-- Pair the orphan Binance leg with an estimated Naranja X receipt at rate 1,450 (≈116,000 ARS).
UPDATE transaction
   SET title = 'P2P sale to Naranja X (USDT → ARS)',
       description = CONCAT(description, ' — proceeds to Naranja X (better rate that day)')
 WHERE id = 'd441f8c9d91064ad16766f4b9883'
   AND user_id = 'ccmFgIVugBYdPlgabAIwiHZztTA2';

   is_paid, paid_ts, source, status)
VALUES
  ('naranja-p2p-2026-01-11-est-01', 'ccmFgIVugBYdPlgabAIwiHZztTA2',
   'P2P receipt (ARS from Binance)',
   'Estimated 80 USDT × 1450 ≈ 116,000 ARS — exact amount unknown (Naranja X had a better rate)',
   116000.00, 'ARS', 'transfer',
   '08fb11396c3d4ac0a703e945036f',  -- Naranja X - Pesos
   'e945321c9cb6177adeabe150cd38',  -- same transfer_id as the Binance -80 USDT leg
   1, '2026-01-11 21:03:50', 'manual', 'reviewed');

-- The /api/transactions list filter uses due_ts (not paid_ts). All inserts above
-- only set paid_ts, so without this backfill the analytics charts would skip them.
-- Mirrors the convention used by the rest of the table for paid rows.
UPDATE transaction
   SET due_ts = paid_ts
 WHERE user_id = 'ccmFgIVugBYdPlgabAIwiHZztTA2'
   AND due_ts IS NULL
   AND paid_ts IS NOT NULL
   AND (description LIKE 'Deel%'
        OR description LIKE 'Binance %'
        OR description LIKE 'MP credit%'
        OR description LIKE 'Galicia%'
        OR description LIKE 'Estimated%'
        OR description LIKE '%proceeds to Naranja%');
